// Rakko API response から BQ 用の行を生成
// 注: HTTP node は item ごとに 1 回呼ばれる前提 (n8n の標準動作)

const now = new Date().toISOString();
const todayJST = new Date(Date.now() + 9*60*60*1000).toISOString().split('T')[0];
const targetItems = $('Code: Target URL List').all();
const rows = [];

for (let i = 0; i < $input.all().length; i++) {
  const resp = $input.all()[i].json;
  const targetInfo = targetItems[i].json;
  const targetUrl = targetInfo.target_url;
  const matchType = targetInfo.match_type;
  const domain = targetUrl.replace(/^https?:\/\//, '').split('/')[0];
  const items = (resp && resp.data && resp.data.items) || [];

  for (const it of items) {
    const m = it.metrics || {};
    rows.push({
      fetched_date: todayJST,
      target_url: targetUrl,
      match_type: matchType,
      domain: domain,
      keyword: it.keyword || '',
      search_volume: m.searchVolume != null ? Number(m.searchVolume) : null,
      seo_difficulty: m.seoDifficulty != null ? Number(m.seoDifficulty) : null,
      cpc: m.cpc != null ? Number(m.cpc) : null,
      competition: m.competition != null ? Number(m.competition) : null,
      rank: m.rank != null ? Number(m.rank) : null,
      etv: m.etv != null ? Number(m.etv) : null,
      inserted_at: now
    });
  }
}

return rows.map(json => ({ json }));
